class TestOpenSavingsAccountHappyPath:

    def test_returns_savings_account_object(
        self, service, verified_customer, idempotency_key
    ):
        account = open_account(
            service, verified_customer.customer_id, 500, idempotency_key
        )
        assert isinstance(account, SavingsAccount)

    def test_account_is_active(
        self, service, verified_customer, idempotency_key
    ):
        account = open_account(
            service, verified_customer.customer_id, 500, idempotency_key
        )
        assert account.status == AccountStatus.ACTIVE

    def test_account_linked_to_customer(
        self, service, verified_customer, idempotency_key
    ):
        account = open_account(
            service, verified_customer.customer_id, 500, idempotency_key
        )
        assert account.customer_id == verified_customer.customer_id

    def test_account_balance_matches_opening_deposit(
        self, service, verified_customer, idempotency_key
    ):
        account = open_account(
            service, verified_customer.customer_id, 500, idempotency_key
        )
        assert account.balance == Decimal("500")

    def test_account_id_is_assigned(
        self, service, verified_customer, idempotency_key
    ):
        account = open_account(
            service, verified_customer.customer_id, 500, idempotency_key
        )
        assert account.account_id and len(account.account_id) > 0

    def test_account_is_persisted(
        self, service, verified_customer, idempotency_key, mock_account_repo
    ):
        account = open_account(
            service, verified_customer.customer_id, 500, idempotency_key
        )
        mock_account_repo.save.assert_called_once_with(account)


