class TestMinimumBalanceEnforcement:

    @pytest.mark.parametrize("balance", [100, 100.01, 500, 1000, 99999.99])
    def test_valid_opening_balances_are_accepted(
        self, service, verified_customer, balance
    ):
        key = str(uuid.uuid4())
        account = open_account(
            service, verified_customer.customer_id, balance, key
        )
        assert account.balance >= MINIMUM_OPENING_BALANCE

    @pytest.mark.parametrize("balance", [0, 0.01, 50, 99, 99.99])
    def test_below_minimum_balance_raises_error(
        self, service, verified_customer, balance
    ):
        key = str(uuid.uuid4())
        with pytest.raises(InsufficientOpeningBalanceError):
            open_account(service, verified_customer.customer_id, balance, key)

    def test_exactly_minimum_balance_is_accepted(
        self, service, verified_customer
    ):
        key = str(uuid.uuid4())
        account = open_account(
            service, verified_customer.customer_id, 100, key
        )
        assert account.balance == MINIMUM_OPENING_BALANCE

    def test_zero_balance_raises_error(self, service, verified_customer):
        key = str(uuid.uuid4())
        with pytest.raises(InsufficientOpeningBalanceError):
            open_account(service, verified_customer.customer_id, 0, key)

    def test_negative_balance_raises_error(self, service, verified_customer):
        key = str(uuid.uuid4())
        with pytest.raises(InsufficientOpeningBalanceError):
            open_account(service, verified_customer.customer_id, -50, key)


