# 3. Tiered interest-rate assignment
# ===========================================================================

class TestTieredInterestRates:
    """
    Tier table:
        >= $100,000  → 5 %
        >= $10,000   → 3 %
        >= $1,000    → 2 %
        >= $100      → 1 %
    """

    @pytest.mark.parametrize("balance,expected_rate", [
        (100,       Decimal("0.01")),   # floor tier
        (999.99,    Decimal("0.01")),
        (1_000,     Decimal("0.02")),   # second tier boundary
        (9_999.99,  Decimal("0.02")),
        (10_000,    Decimal("0.03")),   # third tier boundary
        (99_999.99, Decimal("0.03")),
        (100_000,   Decimal("0.05")),   # top tier boundary
        (500_000,   Decimal("0.05")),
    ])
    def test_interest_rate_tier_assignment(
        self, service, verified_customer, balance, expected_rate
    ):
        key = str(uuid.uuid4())
        account = open_account(
            service, verified_customer.customer_id, balance, key
        )
        assert account.interest_rate == expected_rate, (
            f"Balance {balance} should yield rate {expected_rate}, "
            f"got {account.interest_rate}"
        )

    def test_interest_rate_is_persisted_on_account(
        self, service, verified_customer
    ):
        key = str(uuid.uuid4())
        account = open_account(
            service, verified_customer.customer_id, 1500, key
        )
        assert account.interest_rate == Decimal("0.02")

    def test_interest_rate_applied_automatically_without_caller_input(
        self, service, verified_customer
    ):
        """Caller does NOT supply an interest rate; service derives it."""
        key = str(uuid.uuid4())
        # open_account signature has no rate parameter
        import inspect
        sig = inspect.signature(service.open_account)
        assert "interest_rate" not in sig.parameters


