class TestIdempotency:

    def test_duplicate_key_returns_identical_account_object(
        self, service, verified_customer, idempotency_key
    ):
        first  = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        second = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        assert first is second  # exact same object from cache

    def test_duplicate_key_returns_same_account_id(
        self, service, verified_customer, idempotency_key
    ):
        first  = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        second = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        assert first.account_id == second.account_id

    def test_duplicate_key_returns_same_balance(
        self, service, verified_customer, idempotency_key
    ):
        first  = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        second = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        assert first.balance == second.balance

    def test_duplicate_key_returns_same_interest_rate(
        self, service, verified_customer, idempotency_key
    ):
        first  = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        second = open_account(service, verified_customer.customer_id, 300, idempotency_key)
        assert first.interest_rate == second.interest_rate

    def test_duplicate_submission_does_not_create_second_account(
        self, service, verified_customer, idempotency_key, mock_account_repo
    ):
        open_account(service, verified_customer.customer_id, 300, idempotency_key)
        open_account(service, verified_customer.customer_id, 300, idempotency_key)
        # persist called exactly once
        mock_account_repo.save.assert_called_once()

    def test_idempotency_store_consulted_on_every_call(
        self, service, verified_customer, idempotency_key, idempotency_store
    ):
        open_account(service, verified_customer.customer_id, 300, idempotency_key)
        open_account(service, verified_customer.customer_id, 300, idempotency_key)
        assert idempotency_store.get.call_count == 2

    def test_idempotency_store_written_only_once(
        self, service, verified_customer, idempotency_key, idempotency_store
    ):
        open_account(service, verified_customer.customer_id, 300, idempotency_key)
        open_account(service, verified_customer.customer_id, 300, idempotency_key)
        idempotency_store.store.assert_called_once()

    def test_different_keys_produce_different_accounts(
        self, service, verified_customer
    ):
        key_a = str(uuid.uuid4())
        key_b = str(uuid.uuid4())
        account_a = open_account(service, verified_customer.customer_id, 300, key_a)
        account_b = open_account(service, verified_customer.customer_id, 300, key_b)
        assert account_a.account_id != account_b.account_id

    def test_idempotency_key_stored_on_account(
        self, service, verified_customer, idempotency_key
    ):
        account = open_account(
            service, verified_customer.customer_id, 300, idempotency_key
        )
        assert account.idempotency_key == idempotency_key

    def test_many_duplicate_submissions_all_return_original(
        self, service, verified_customer, idempotency_key
    ):
        original = open_account(
            service, verified_customer.customer_id, 300, idempotency_key
        )
        for _ in range(10):
            result = open_account(
                service, verified_customer.customer_id, 300, idempotency_key
            )
            assert result.account_id == original.account_id

    def test_duplicate_with_different_balance_still_returns_original(
        self, service, verified_customer, idempotency_key
    ):
        """
        The idempotency key is the authority – even if the caller
        accidentally sends a different payload, the original result is returned.
        """
        original = open_account(
            service, verified_customer.customer_id, 300, idempotency_key
        )
        duplicate = open_account(
            service, verified_customer.customer_id, 9999, idempotency_key
        )
        assert duplicate.account_id == original.account_id
        assert duplicate.balance == Decimal("300")   # original balance preserved

    def test_failed_request_is_not_cached(
        self, service, unverified_customer, idempotency_store
    ):
        """
        A request that raises an error must NOT be stored in the
        idempotency cache so a corrected retry can succeed.
        """
        key = str(uuid.uuid4())
        with pytest.raises(CustomerNotVerifiedError):
            open_account(service, unverified_customer.customer_id, 200, key)
        idempotency_store.store.assert_not_called()


