class TestResolveInterestRate:

    @pytest.mark.parametrize("balance,expected", [
        (Decimal("100"),       Decimal("0.01")),
        (Decimal("999.99"),    Decimal("0.01")),
        (Decimal("1000"),      Decimal("0.02")),
        (Decimal("9999.99"),   Decimal("0.02")),
        (Decimal("10000"),     Decimal("0.03")),
        (Decimal("99999.99"),  Decimal("0.03")),
        (Decimal("100000"),    Decimal("0.05")),
        (Decimal("1000000"),   Decimal("0.05")),
    ])
    def test_rate_boundaries(self, balance, expected):
        assert _resolve_interest_rate(balance) == expected

    def test_below_minimum_raises(self):
        with pytest.raises(InsufficientOpeningBalanceError):
            _resolve_interest_rate(Decimal("99.99"))

    def test_zero_raises(self):
        with pytest.raises(InsufficientOpeningBalanceError):
            _resolve_interest_rate(Decimal("0"))
